            .into_iter()
            .chain(toggle.pending_effects)
            .chain(reset.pending_effects)
        {
            drop(effect.run(service.context(), service.props(), Arc::clone(&send)));
        }

        assert_eq!(*changes.lock().unwrap(), vec![false, true, true]);
    }

